#include <stdio.h>
#include <string.h>

#define MSG_SIZE 64
#define QUEUE_LEN 4

// ★ Stage 0 — Exemple complet
typedef struct {
    long mtype;          // ★ identifiant de canal/priorité
    char mtext[MSG_SIZE]; // ★ contenu du message
} MsgBuf;

MsgBuf queue[QUEUE_LEN];
int qhead = 0, qtail = 0;

void msgsnd_sim(long type, const char *text) {
    queue[qtail].mtype = type;                      // ★ stocker le type
    strncpy(queue[qtail].mtext, text, MSG_SIZE - 1); // ★ copier le texte
    qtail++;                                         // ★ avancer la queue
}

int msgrcv_sim(MsgBuf *out) {
    if (qhead >= qtail) return -1;  // ★ file vide
    *out = queue[qhead++];          // ★ lire et avancer la tête
    return 0;
}

int main(void) {
    msgsnd_sim(1, "hello queue");   // ★ enfiler un message type=1
    MsgBuf msg;
    msgrcv_sim(&msg);               // ★ défiler
    printf("mtype=%ld mtext=%s\n", msg.mtype, msg.mtext);
    return 0;
}

